using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex throws in EF Core 9 Cosmos — manage indexing via Azure portal/Bicep.
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", so we must preserve the old name
        // to keep them readable — and to keep direct SQL queries (c.Discriminator) working.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "Product|123" to just "123".
        // Existing documents use the compound format, so we must preserve it
        // or FindAsync/point-reads will fail against existing data.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

