{
    // Sync I/O on the Cosmos provider now throws in EF Core 9.
    // All queries must use async equivalents (ToListAsync, etc.).
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (preserved via HasDiscriminator above).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

