5.     protected override void OnModelCreating(ModelBuilder modelBuilder)
6.     {
7.         // HasIndex throws in EF Core 9 Cosmos — manage indexing via Azure portal/Bicep.
8.         modelBuilder.Entity<Product>().ToContainer("Products");
